export declare function main(writer: Writer<string>, feedname: string, flush: boolean, dump: string | Buffer, dumpContentType: string, focusNodesStrategy: 'extract' | 'sparql' | 'iris', nodeShapeIri: string, nodeShape?: string, focusNodes?: string, dbDir?: string): Promise<void>;
